module fsm (
    input IN,
    input CLK,
    input RST,
    output reg MATCH
);
    parameter STATE_IDLE = 3'b000;
    parameter STATE_1 = 3'b001;
    parameter STATE_10 = 3'b010;
    parameter STATE_100 = 3'b011;
    parameter STATE_1001 = 3'b100;
    reg [2:0] state, next_state;

    always @(posedge CLK or posedge RST) begin
        if (RST) begin
            state <= STATE_IDLE;
            MATCH <= 1'b0;
        end
        else begin
            state <= next_state;
            MATCH <= (next_state == STATE_1001) ? 1'b1 : 1'b0;
        end
    end

    always @(*) begin
        case (state)
            STATE_IDLE: begin
                if (IN) next_state = STATE_1;
                else next_state = STATE_IDLE;
            end
            STATE_1: begin
                if (IN) next_state = STATE_1;
                else next_state = STATE_10;
            end
            STATE_10: begin
                if (IN) next_state = STATE_1;
                else next_state = STATE_100;
            end
            STATE_100: begin
                if (IN) next_state = STATE_1001;
                else next_state = STATE_IDLE;
            end
            STATE_1001: begin
                if (IN) next_state = STATE_1;
                else next_state = STATE_10;
            end
            default: next_state = STATE_IDLE;
    endcase
end // Auto-repaired
endmodule
